module top_module (
    input k,
    input w,
    input t,
    output reg invalid_output
);
    always @(*) begin
        case ({k, w, t})
            3'b000: invalid_output = 1'b1;
            3'b101: invalid_output = 1'b1;
            3'b001: invalid_output = 1'b0;
            3'b110: invalid_output = 1'b1;
            3'b010: invalid_output = 1'b0;
            3'b100: invalid_output = 1'b1;
            3'b111: invalid_output = 1'b1;
            3'b011: invalid_output = 1'b1;
        endcase
    end
endmodule
